import { ExternalTokenizer } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';
import { InvalidPositionOperator, PositionOperator } from '../parser.terms.js';

const { ASTERISK } = characterCodes;

/** @internal */
export const positionOperatorTokenizer = new ExternalTokenizer(
  (inputStream, stack) => {
    // No asterisk, definitely not a position operator.
    if (inputStream.next !== ASTERISK) {
      return;
    }

    if (
      stack.context.lastToken === null ||
      stack.context.lastToken === 'expression'
    ) {
      return;
    }

    // Current character is an asterisk.
    // Advance input stream by 1.
    inputStream.advance();

    let additionalOperators = 0;
    // As long as we keep hitting asterisks (or the end of the input),
    // keep going to include all the characters in the position operator token.
    while (inputStream.next === ASTERISK) {
      // Move on to the next character.
      inputStream.advance();
      additionalOperators += 1;
    }

    // Accept either a valid or invalid position operator, depending on the asterisks encountered.
    inputStream.acceptToken(
      additionalOperators === 0 ? PositionOperator : InvalidPositionOperator,
    );
  },
);
